      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projects = {};

function create(projectData) {
  const id = randomUUID();
  if (Object.values(projects).some(p => p.name === projectData.name)) {
    throw { code: 'duplicate', message: 'Project already exists' };
  }
  projects[id] = { ...projectData, id };
  return projects[id];
}

function getAll() {
  return Object.values(projects);
}

function getById(id) {
  const project = projects[id];
  if (!project) {
    throw { code: 'not_found', message: 'Project not found' };
  }
  return project;
}

module.exports = { create, getAll, getById };
