      "content": "const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const members = {};

function create(projectId, memberData) {
  const project = projectsService.getById(projectId);
  const id = `${projectId}-${randomUUID()}`;
  if (members[projectId]?.some(m => m.userId === memberData.userId)) {
    throw { code: 'duplicate', message: 'Member already exists in this project' };
  }
  members[projectId] = [...(members[projectId] || []), { ...memberData, id }];
  return members[projectId].find(m => m.id === id);
}

function getAll(projectId) {
  projectsService.getById(projectId);
  return members[projectId] || [];
}

module.exports = { create, getAll };
