      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const tasks = {};

function create(projectId, taskData) {
  const project = projectsService.getById(projectId);
  const id = `${projectId}-${randomUUID()}`;
  tasks[projectId] = [...(tasks[projectId] || []), { ...taskData, id, status: 'pending' }];
  return tasks[projectId].find(t => t.id === id);
}

function getAll(projectId, status) {
  projectsService.getById(projectId);
  const projectTasks = tasks[projectId] || [];
  if (status) {
    return projectTasks.filter(t => t.status === status);
  }
  return projectTasks;
}

function update(projectId, taskId, taskData) {
  projectsService.getById(projectId);
  const taskIndex = tasks[projectId]?.findIndex(t => t.id === taskId);
  if (taskIndex === -1) {
    throw { code: 'not_found', message: 'Task not found' };
  }
  tasks[projectId][taskIndex] = { ...tasks[projectId][taskIndex], ...taskData };
  return tasks[projectId][taskIndex];
}

module.exports = { create, getAll, update };
