  switch (error.code) {
    case 'not_found':
      res.status(404).json({ message: error.message });
      break;
    case 'duplicate':
      res.status(409).json({ message: error.message });
      break;
    default:
      res.status(500).json({ message: 'Internal server error' });
  }
}

module.exports = { errorHandler };
